        "source_report": source_report,
        "count": len(merged),
        "max_entries": int(max_entries),
        "evicted_entries": int(evicted),
        "items": [asdict(c) for c in merged],
        "ts": time.time(),
    }
    p.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    return payload


